const detectSchemaDrift = (nodeOutputs: any[]) => {
  const expectedSchema = {
    type: 'object',
    properties: { action: {type: 'string'}, params: {type: 'object'} },
    required: ['action', 'params']
  };

  return nodeOutputs.map((output, idx) => {
    try {
      const isValid = validate(output.json, expectedSchema);
      return {
        execution: idx,
        consistent: isValid,
        output: output.json,
        error: isValid ? null : 'Schema mismatch',
        driftScore: isValid ? 0 : 1
      };
    } catch (e) {
      return { execution: idx, consistent: false, error: e.message, driftScore: 1 };
    }
  }).filter(r => !r.consistent);
};

// Run in n8n Code node after AI Agent
const workflowData = $workflow.staticData;
const detectRecursion = () => {
  const aiNodes = $workflow.nodes.filter(n => n.type.includes('ai-agent'));
  const triggers = [];

  aiNodes.forEach(aiNode => {
    aiNode.connections.forEach(conn => {
      conn.forEach(target => {
        if (target.node.type.includes('ai-agent') && 
            target.node.parameters.model === aiNode.parameters.model) {
          triggers.push({
            from: aiNode.name,
            to: target.node.name,
            risk: 'HIGH',
            pattern: 'ai-agent -> ai-agent recursion'
          });
        }
      });
    });
  });

  return { recursiveTriggers: triggers, count: triggers.length };
};

const analyzeVariance = (executions: any[]) => {
  const structures = executions.map(exec => 
    JSON.stringify(Object.keys(exec.json).sort())
  );

  const uniqueStructures = new Set(structures);
  const varianceScore = uniqueStructures.size / structures.length;

  return {
    varianceScore,
    uniqueStructures: Array.from(uniqueStructures),
    executions,
    isConsistent: varianceScore < 0.1,
    recommendation: varianceScore > 0.3 ? 'CRITICAL: Add JSON mode enforcement' : 'OK'
  };
};

