// Place after every AI Agent node
const validateAgentOutput = ($input) => {
  const expectedSchema = z.object({
    action: z.enum(['email', 'sms', 'db_update']),
    params: z.object({}),
    reasoning: z.string().optional()
  });

  const results = $input.all().map(item => {
    const parsed = expectedSchema.safeParse(item.json);

    if (!parsed.success) {
      // Fallback to safe default
      return {
        json: {
          action: 'noop',
          params: {},
          reasoning: `Validation failed: ${parsed.error.message}`,
          validated: false
        }
      };
    }

    return { json: { ...parsed.data, validated: true } };
  });

  return results;
};

// Memory Window Node -> Code Node pipeline
const normalizeMemoryContext = ($input) => {
  const normalized = $input.all().map(item => {
    const messages = item.json.messages || [];

    return {
      json: {
        context: {
          conversationId: item.json.conversationId || 'default',
          timestamp: new Date().toISOString(),
          messages: messages.slice(-10).map(msg => ({ // Last 10 messages only
            role: msg.role,
            content: msg.content,
            timestamp: msg.timestamp || new Date().toISOString()
          })),
          validated: true
        }
      }
    };
  });

  return normalized;
};

